sys_script_include.script:
var AppleAppStoreAPICall = Class.create();
AppleAppStoreAPICall.prototype = Object.extendsObject(AbstractAjaxProcessor, {

    callAPI: function() {

        var appId = this.getParameter('sysparm_appId');

        if (!appId)
            return "App not found";

        var request = new sn_ws.RESTMessageV2();
        request.setHttpMethod('GET');
        request.setEndpoint('https://itunes.apple.com/lookup?id=' + appId);

        var response = request.execute();
        var body = response.getBody();
        var parsed = JSON.parse(body);

        if (!parsed.results || parsed.results.length === 0)
            return "App not found";

        var appArr = [
            parsed.results[0].trackName,
            parsed.results[0].version,
            parsed.results[0].artistName
        ];

        return JSON.stringify(appArr);
    },

    type: 'AppleAppStoreAPICall'
});
